import { createServerSupabase } from '@/lib/supabaseServer';
import { AppShell } from '@/components/AppShell';
export default async function Plano(){const supabase=createServerSupabase();const {data=[]}=await supabase.from('meal_plans').select('*').order('day_number');return <AppShell><h1 className="text-4xl font-black">Plano alimentar de 14 dias</h1><p className="mt-2 rounded-2xl bg-amber-50 p-4 text-amber-800">Plano geral para reeducação alimentar. Não substitui avaliação e acompanhamento com nutricionista.</p><div className="mt-6 grid gap-4">{data.map((d:any)=><div className="card" key={d.id}><span className="badge">Dia {d.day_number}</span><h2 className="mt-3 text-xl font-black">Cardápio do dia</h2><div className="mt-3 grid gap-2 text-sm md:grid-cols-2"><p><b>Café:</b> {d.breakfast}</p><p><b>Lanche manhã:</b> {d.morning_snack}</p><p><b>Almoço:</b> {d.lunch}</p><p><b>Lanche tarde:</b> {d.afternoon_snack}</p><p><b>Jantar:</b> {d.dinner}</p><p><b>Ceia:</b> {d.supper}</p></div><p className="mt-3 text-slate-600">{d.notes}</p></div>)}</div></AppShell>}
